protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's
    // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
    // EF Core 9 throws InvalidOperationException if HasIndex is called.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator")
    // so existing documents and direct SQL queries (c.Discriminator) keep working.
    // EF Core 9 defaults to "$type".
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123")
    // so existing documents remain accessible via FindAsync / point-reads.
    // EF Core 9 defaults to key-only ids ("123").
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

